RUN cat > /workspace/graphlib.py <<'EOF'
def dfs(graph, start, end):
    """Check if there is a path from start to end in the directed graph."""
    def _dfs_helper(node, target, visited):
        if node == target:
            return True
        visited.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                if _dfs_helper(neighbor, target, visited):
                    return True
        return False

    return _dfs_helper(start, end, set())
EOF

RUN cat > /workspace/test_graph.py <<'EOF'
from graphlib import dfs

def test_simple_path():
    graph = {
        'A': ['B'],
        'B': ['C'],
        'C': []
    }
    assert dfs(graph, 'A', 'C') == True
    assert dfs(graph, 'C', 'A') == False

def test_cycle_handling():
    graph = {
        'A': ['B'],
        'B': ['C'],
        'C': ['A']  # Cycle back to A
    }
    assert dfs(graph, 'A', 'C') == True
    assert dfs(graph, 'A', 'A') == True  # Start equals end

def test_disconnected_nodes():
    graph = {
        'A': ['B'],
        'B': [],
        'C': ['D'],
        'D': []
    }
    assert dfs(graph, 'A', 'D') == False
    assert dfs(graph, 'C', 'D') == True
EOF
RUN cd /workspace && git add -A && git commit -q -m "skillrace: test setup" || true
